sql:
SELECT DISTINCT location_id
FROM weather_data
WHERE wind_speed_9am > 20 OR wind_speed_3pm > 20;

SELECT COUNT(*) AS TotalOnlineLogs
FROM data_collection_logs
WHERE collection_method = 'online';

SELECT * 
FROM weather_data 
ORDER BY min_temp DESC;

external_knowledge:
"Chilliest corners" refers to the locations with the lowest average temperature;
"Explorers" metaphorically represents the users who accessed the weather data;
"Based on the average coldness felt" means that the average temperature was calculated from the minimum and maximum temperatures recorded at each location.
